    private ProcessingResult validateDocument(Document document) {
        ProcessingResult result = new ProcessingResult();
        Element root = document.getDocumentElement();
        List<String> validationErrors = new ArrayList<>();

        // Validate required structure
        if (root.getElementsByTagName("header").getLength() == 0) {
            validationErrors.add("Missing required 'header' element");
        }
        if (root.getElementsByTagName("body").getLength() == 0) {
            validationErrors.add("Missing required 'body' element");
        }

        // Validate header contents
        NodeList headers = root.getElementsByTagName("header");
        if (headers.getLength() > 0) {
            Element header = (Element) headers.item(0);
            if (getElementText(header, "source-system") == null) {
                validationErrors.add("Missing 'source-system' in header");
            }
            if (getElementText(header, "timestamp") == null) {
                validationErrors.add("Missing 'timestamp' in header");
            }
        }

        result.setSuccess(validationErrors.isEmpty());
        result.setMessage(validationErrors.isEmpty() ?
                "Document validation passed" :
                "Validation failed with " + validationErrors.size() + " errors");
        result.setValidationErrors(validationErrors);
        return result;
    }

    private ProcessingResult transformDocument(Document document) {
        ProcessingResult result = new ProcessingResult();
        Element root = document.getDocumentElement();

        StringBuilder transformed = new StringBuilder();
        transformed.append("{\"transformed\": {");

        NodeList children = root.getChildNodes();
        boolean first = true;
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                if (!first) transformed.append(", ");
                transformed.append("\"").append(child.getNodeName()).append("\": ");
                transformed.append("\"").append(escapeJsonString(child.getTextContent().trim())).append("\"");
                first = false;
            }
        }

        transformed.append("}}");

        result.setSuccess(true);
        result.setMessage("Document transformed successfully");
        result.setProcessedData(transformed.toString());
        return result;
    }

    private String escapeJsonString(String input) {
        if (input == null) return "";
        return input.replace("\\", "\\\\")
                .replace("\"", "\\\"")
                .replace("\n", "\\n")
                .replace("\r", "\\r")
                .replace("\t", "\\t");
    }

    private Map<String, String> parseRecordElement(Element recordElement) {
        Map<String, String> recordData = new HashMap<>();

        // Parse record ID attribute
        if (recordElement.hasAttribute("id")) {
            recordData.put("id", recordElement.getAttribute("id"));
        }

        // Parse all child elements as key-value pairs
        NodeList fields = recordElement.getChildNodes();
        for (int i = 0; i < fields.getLength(); i++) {
            Node field = fields.item(i);
            if (field.getNodeType() == Node.ELEMENT_NODE) {
                String fieldName = field.getNodeName();
                String fieldValue = field.getTextContent().trim();
                recordData.put(fieldName, fieldValue);
            }
        }

        return recordData;
    }

    private void processEntityGroup(Element groupElement, List<Map<String, String>> records, List<String> errors) {
        String groupName = groupElement.getAttribute("name");
        String groupType = groupElement.getAttribute("type");

        LOGGER.info("Processing entity group: " + groupName + " (type: " + groupType + ")");

        NodeList entities = groupElement.getElementsByTagName("entity");
        for (int i = 0; i < entities.getLength(); i++) {
            Node entityNode = entities.item(i);
            if (entityNode.getNodeType() == Node.ELEMENT_NODE) {
                try {
                    Map<String, String> entityData = parseRecordElement((Element) entityNode);
                    entityData.put("_group", groupName);
                    entityData.put("_groupType", groupType);
                    records.add(entityData);
                } catch (Exception e) {
                    errors.add("Entity in group '" + groupName + "': " + e.getMessage());
                }
            }
        }

        // Process nested sub-groups
        NodeList subGroups = groupElement.getChildNodes();
        for (int i = 0; i < subGroups.getLength(); i++) {
            Node subGroupNode = subGroups.item(i);
            if (subGroupNode.getNodeType() == Node.ELEMENT_NODE &&
                    "entity-group".equals(subGroupNode.getNodeName())) {
                processEntityGroup((Element) subGroupNode, records, errors);
            }
        }
    }

    private String getElementText(Element parent, String tagName) {
        NodeList nodes = parent.getElementsByTagName(tagName);
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent().trim();
        }
        return null;
    }

